import { resolve, join } from 'node:path'
import { readdir, readFile, writeFile, mkdir, copyFile, chmod } from 'node:fs/promises'
import { readFileSync } from 'node:fs'
import { fileURLToPath } from 'node:url'

const thisFile = fileURLToPath(import.meta.url)
const pkgJson = JSON.parse(readFileSync(resolve(thisFile, '..', '..', 'package.json'), 'utf-8'))
const SDK_VERSION: string = pkgJson.version

interface ScaffoldOptions {
	name: string
	slug: string
}

const TEMPLATE_EXTENSIONS = new Set([
	'.ts', '.tsx', '.js', '.jsx', '.json', '.md', '.css', '.mjs', '.html',
])

export async function scaffold(options: ScaffoldOptions): Promise<void> {
	const thisDir = resolve(fileURLToPath(import.meta.url), '..')
	const templateDir = resolve(thisDir, '..', 'template')
	const targetDir = resolve(process.cwd(), options.slug)

	await mkdir(targetDir, { recursive: true })

	const replacements: Record<string, string> = {
		'{{CLIENT_NAME}}': options.name,
		'{{CLIENT_SLUG}}': options.slug,
		'{{SDK_VERSION}}': SDK_VERSION,
	}

	await copyDir(templateDir, targetDir, replacements)

	// Ensure Husky hooks are executable (npm pack may strip the executable bit)
	const huskyDir = join(targetDir, '.husky')
	const huskyEntries = await readdir(huskyDir).catch(() => [])
	for (const hook of huskyEntries) {
		if (!hook.startsWith('_')) {
			await chmod(join(huskyDir, hook), 0o755)
		}
	}

	// .env.local is already created by copyDir (renamed from .env.local.template with placeholders replaced)
}

function applyReplacements(content: string, replacements: Record<string, string>): string {
	let result = content
	for (const [placeholder, value] of Object.entries(replacements)) {
		result = result.replaceAll(placeholder, value)
	}
	return result
}

async function copyDir(
	src: string,
	dest: string,
	replacements: Record<string, string>,
): Promise<void> {
	await mkdir(dest, { recursive: true })
	const entries = await readdir(src, { withFileTypes: true })

	for (const entry of entries) {
		const srcPath = join(src, entry.name)
		let destName = entry.name

		// Rename .template files by stripping the extension
		if (destName.endsWith('.template')) {
			destName = destName.slice(0, -'.template'.length)
		}

		// npm strips .gitignore from packages, so we ship it as "gitignore"
		if (destName === 'gitignore') {
			destName = '.gitignore'
		}

		// npm strips dotfiles/dotdirs, so we ship "husky" and rename to ".husky"
		if (destName === 'husky') {
			destName = '.husky'
		}

		const destPath = join(dest, destName)

		if (entry.isDirectory()) {
			await copyDir(srcPath, destPath, replacements)
		} else {
			const ext = '.' + destName.split('.').pop()
			if (TEMPLATE_EXTENSIONS.has(ext) || entry.name.endsWith('.template')) {
				const content = await readFile(srcPath, 'utf-8')
				await writeFile(destPath, applyReplacements(content, replacements), 'utf-8')
			} else {
				await copyFile(srcPath, destPath)
			}
		}
	}
}
