import * as p from '@clack/prompts'
import { scaffold } from './scaffold'

async function main() {
	p.intro('Growth Engine — Create Client App')

	const project = await p.group(
		{
			name: () =>
				p.text({
					message: 'Client name:',
					placeholder: 'Restaurant Bella',
					validate: (v) => (v.length === 0 ? 'Name is required' : undefined),
				}),
			slug: () =>
				p.text({
					message: 'Client slug:',
					placeholder: 'restaurant-bella',
					validate: (v) =>
						/^[a-z0-9-]+$/.test(v) ? undefined : 'Slug must be lowercase alphanumeric with dashes',
				}),
		},
		{
			onCancel: () => {
				p.cancel('Setup cancelled.')
				process.exit(0)
			},
		},
	)

	const spinner = p.spinner()
	spinner.start('Scaffolding project...')

	await scaffold({
		name: project.name as string,
		slug: project.slug as string,
	})

	spinner.stop('Project scaffolded!')

	p.note(
		`cd ${project.slug as string}\n# Copy .env.example to .env.local and fill in your credentials\ncp .env.example .env.local\nnpm install\nnpm run dev`,
		'Next steps',
	)

	p.outro('Done!')
}

void main()
